// Event types
type Event = DepositEvent | WithdrawEvent | TransferEvent;

interface DepositEvent {
  type: 'deposit';
  accountId: string;
  amount: number;
  timestamp: Date;
}

interface WithdrawEvent {
  type: 'withdraw';
  accountId: string;
  amount: number;
  timestamp: Date;
}

interface TransferEvent {
  type: 'transfer';
  fromAccountId: string;
  toAccountId: string;
  amount: number;
  timestamp: Date;
}

// Account aggregate
class Account {
  private accountId: string;
  private balance: number = 0;
  private events: Event[] = [];

  constructor(accountId: string) {
    this.accountId = accountId;
  }

  deposit(amount: number): void {
    if (amount <= 0) {
      throw new Error('Deposit amount must be positive');
    }
    this.balance += amount;
    this.events.push({
      type: 'deposit',
      accountId: this.accountId,
      amount,
      timestamp: new Date()
    });
  }

  withdraw(amount: number): void {
    if (amount <= 0) {
      throw new Error('Withdrawal amount must be positive');
    }
    if (amount > this.balance) {
      throw new Error('Insufficient funds');
    }
    this.balance -= amount;
    this.events.push({
      type: 'withdraw',
      accountId: this.accountId,
      amount,
      timestamp: new Date()
    });
  }

  transfer(toAccountId: string, amount: number): void {
    if (amount <= 0) {
      throw new Error('Transfer amount must be positive');
    }
    if (amount > this.balance) {
      throw new Error('Insufficient funds for transfer');
    }
    this.balance -= amount;
    this.events.push({
      type: 'transfer',
      fromAccountId: this.accountId,
      toAccountId,
      amount,
      timestamp: new Date()
    });
  }

  getBalance(): number {
    return this.balance;
  }

  getEvents(): Event[] {
    return [...this.events];
  }

  loadFromEvents(events: Event[]): void {
    this.balance = 0;
    this.events = [];
    for (const event of events) {
      if (event.type === 'deposit' && event.accountId === this.accountId) {
        this.balance += event.amount;
      } else if (event.type === 'withdraw' && event.accountId === this.accountId) {
        this.balance -= event.amount;
      } else if (event.type === 'transfer') {
        if (event.fromAccountId === this.accountId) {
          this.balance -= event.amount;
        } else if (event.toAccountId === this.accountId) {
          this.balance += event.amount;
        }
      }
    }
    this.events = events;
  }
}
```

