export class Account {
  private accountId: string;
  private balance: number = 0;
  private events: Event[] = [];

  constructor(accountId: string) {
    if (!accountId || accountId.trim() === '') {
      throw new Error('Account ID cannot be empty');
    }
    this.accountId = accountId;
  }

  deposit(amount: number): void {
    if (!Number.isFinite(amount) || amount <= 0) {
      throw new InvalidAmountError(amount);
    }

    this.balance += amount;
    this.events.push({
      type: 'deposit',
      accountId: this.accountId,
      amount,
      timestamp: new Date()
    });
  }

  withdraw(amount: number): void {
    if (!Number.isFinite(amount) || amount <= 0) {
      throw new InvalidAmountError(amount);
    }

    if (amount > this.balance) {
      throw new InsufficientFundsError(this.balance, amount);
    }

    this.balance -= amount;
    this.events.push({
      type: 'withdraw',
      accountId: this.accountId,
      amount,
      timestamp: new Date()
    });
  }

  transfer(toAccountId: string, amount: number): void {
    if (!toAccountId || toAccountId.trim() === '') {
      throw new Error('Target account ID cannot be empty');
    }

    if (!Number.isFinite(amount) || amount <= 0) {
      throw new InvalidAmountError(amount);
    }

    if (amount > this.balance) {
      throw new InsufficientFundsError(this.balance, amount);
    }

    this.balance -= amount;
    this.events.push({
      type: 'transfer',
      fromAccountId: this.accountId,
      toAccountId,
      amount,
      timestamp: new Date()
    });
  }

  getBalance(): number {
    return this.balance;
  }

  getEvents(): Event[] {
    return [...this.events];
  }

  getAccountId(): string {
    return this.accountId;
  }

  static fromEvents(accountId: string, events: Event[]): Account {
    if (!accountId || accountId.trim() === '') {
      throw new Error('Account ID cannot be empty');
    }

    const account = new Account(accountId);

    for (const event of events) {
